#include <stdio.h>
int main() {
    int T, X;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &X);
        if (X >= 111 && X <= 444) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

